const crypto = require('crypto');

const secret = $env.TKIF_OUTBOUND_SECRET || '';
const headers = $json.headers || {};
const timestamp = headers['x-tkif-timestamp'] || headers['X-TKIF-Timestamp'] || '';
const signature = headers['x-tkif-signature'] || headers['X-TKIF-Signature'] || '';

if (!secret) {
  return [{ json: { verified: false, error: 'Missing TKIF_OUTBOUND_SECRET in n8n environment' } }];
}
if (!timestamp || !signature) {
  return [{ json: { verified: false, error: 'Missing X-TKIF-Timestamp or X-TKIF-Signature' } }];
}

const now = Math.floor(Date.now() / 1000);
const ts = Number(timestamp);
if (!Number.isFinite(ts)) {
  return [{ json: { verified: false, error: 'Invalid X-TKIF-Timestamp' } }];
}

const toleranceSeconds = Number($env.TKIF_HMAC_TOLERANCE_SECONDS || '300');
if (Math.abs(now - ts) > toleranceSeconds) {
  return [{ json: { verified: false, error: 'Expired signature timestamp' } }];
}

let rawBody = $json.body;
if (typeof rawBody !== 'string') {
  rawBody = JSON.stringify(rawBody || {});
}

const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(`${timestamp}.${rawBody}`).digest('hex');
if (expected.length !== signature.length || !crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(signature))) {
  return [{ json: { verified: false, error: 'Invalid signature' } }];
}

let payload;
try {
  payload = typeof $json.body === 'string' ? JSON.parse($json.body) : ($json.body || {});
} catch (e) {
  return [{ json: { verified: false, error: 'Invalid JSON payload' } }];
}

return [{
  json: {
    verified: true,
    route: headers['x-tkif-route'] || headers['X-TKIF-Route'] || '',
    event: payload.event || 'unknown',
    correlation_id: payload.correlation_id || '',
    tenant_id: payload.tenant_id || null,
    application_id: payload.application_id || null,
    payload
  }
}];
